parameters.text:
=🚨 ALERT — investigate and triage.

Investigation Brief:
- Resource Type: {{ $json.output.resource_type }}
- Resource Name: {{ $json.output.resource_name }}
- Namespace:     {{ $json.output.namespace }}
- Symptom:       {{ $json.output.symptom }}
- Severity:      {{ $json.output.severity }}
- Status:        {{ $json.output.status }}
- Summary:       {{ $json.output.summary }}

Suggested kubectl commands: {{ JSON.stringify($json.output.kubectl_commands) }}
Suggested PromQL queries:   {{ JSON.stringify($json.output.promql_queries) }}

Investigate now. Start with the suggested commands but adapt based on what you find. Run at least one kubectl command and one PromQL query.

Return your findings in this exact format:
SUMMARY: one-line status
SEVERITY: critical / warning / healthy
ROOT_CAUSE: your assessment in 1-2 sentences
CONFIDENCE: high / medium / low
RECOMMENDED_ACTION: specific actionable steps
REQUIRES_APPROVAL: yes/no

assignments.value:
={{ (() => {
  const b = $('Extract Brief').first().json.output;
  const sev = b.severity || 'warning';
  const status = b.status || 'firing';
  const sevEmoji = status === 'resolved' ? '✅' : (sev === 'critical' ? '🔴' : '🟡');
  const statusLabel = status === 'resolved' ? '✅ RESOLVED' : '🚨 FIRING';
  return [
    sevEmoji + ' <b>' + statusLabel + '</b>',
    '',
    '🔧 <b>Resource:</b> ' + b.resource_type + ' / ' + b.resource_name,
    '📍 <b>Namespace:</b> ' + b.namespace,
    '⚡ <b>Severity:</b> ' + sev.toUpperCase(),
    '',
    '📋 <b>Summary:</b> ' + b.summary,
    '',
    '🤖 <b>AI Triage:</b>',
    $json.output,
    '',
    '🕐 ' + new Date().toUTCString()
  ].join('
');
})() }}

=❌ <b>WORKFLOW ERROR — S3 Alert Triage</b>

Error: {{ $json.error?.message || "Unknown failure" }}
Time: {{ new Date().toUTCString() }}

<i>Manual investigation required.</i>

parameters.jsCode:
// Extract the JSON brief from Gemini's response
// With response_mime_type=application/json, Gemini returns valid JSON in parts[0].text
try {
  const raw = $input.first().json.candidates[0].content.parts[0].text;
  const brief = JSON.parse(raw);
  return [{ json: { output: brief } }];
} catch(e) {
  // Fallback — never crash the pipeline
  return [{ json: { output: {
    resource_type: 'unknown',
    resource_name: 'unknown',
    namespace: 'unknown',
    symptom: 'Parser failed: ' + e.message,
    severity: 'warning',
    status: 'firing',
    summary: 'Alert received — Gemini parser error, manual investigation required',
    kubectl_commands: ['get pods -A', 'get events -A --sort-by=.lastTimestamp'],
    promql_queries: ['up']
  }}}];
}
